"""matplotlib.style — style management stubs."""

available = ['default', 'seaborn', 'ggplot', 'bmh', 'dark_background',
             'fivethirtyeight', 'grayscale', 'seaborn-v0_8',
             'seaborn-whitegrid', 'seaborn-darkgrid', 'seaborn-notebook',
             'seaborn-paper', 'seaborn-talk', 'seaborn-poster',
             'tableau-colorblind10', 'Solarize_Light2', 'fast',
             'classic', '_mpl-gallery', '_mpl-gallery-nogrid']

def use(style):
    """Accept but ignore style setting — plotly backend has its own styling."""
    pass

def context(style, after_reset=False):
    """No-op context manager."""
    import contextlib
    return contextlib.nullcontext()

# Also register as core
library = {name: {} for name in available}
